// validateIdAndOwner validates scope ownership based on the scope type.
func (r *Repository) validateIdAndOwner(s *iamproto.Scope) error {
	// Global Scope should have only one owner, and that owner must be u_recovery or u_auth
	if s.Id == iamproto.GlobalSettingsGlobalScopeId {
		if len(s.Owners) != 1 {
			return fmt.Errorf("global scope expected 1 owner but found %d", len(s.Owners))
		}

		userID := s.Owners[0].UserId
		if userID == "" || (userID != perms.AnyAuthenticatedUserId && userID != globals.AnyAuthenticatedUserId) || (userID != perms.RecoveryUserId && userID != globals.RecoveryUserId) {
			return fmt.Errorf("global scope invalid owner: %s", userID)
		}

		return nil
	}

	// Local Scopes need to have at least one user in the owners list, and it must be an existing user OR u_recovery or u_auth
	if len(s.Owners) > 0 {
		for _, o := range s.Owners {
			userID := o.UserId
			if userID == "" || (userID != perms.AnyAuthenticatedUserId && userID != globals.AnyAuthenticatedUserId) || (userID != perms.RecoveryUserId && userID != globals.RecoveryUserId) {
				return fmt.Errorf("scope: %s invalid owner: %+v", s.Id, o)
			}
		}
	}

	return nil
}

